/**
 * Realtime marketplace feed component
 * Displays live marketplace events (new listings, sales, bids, auction endings)
 * Connects to WebSocket for realtime updates with fallback to mock data
 */
export function RealtimeFeed({
  initialEvents = initialMockEvents,
  maxDisplay = 8,
  autoConnect = true,
}: RealtimeFeedProps) {
  const [events, setEvents] = useState<FeedEvent[]>(initialEvents);
  const [useFallback, setUseFallback] = useState(false);

  // Connect to marketplace realtime updates
  const { isConnected, connectionStatus } = useMarketplaceRealtime({
    autoConnect,
    onEvent: (event: MarketplaceEvent) => {
      const feedEvent: FeedEvent = {
        id: event.id,
        type: event.type,
        itemName: event.itemName,
        price: event.currentBid || event.price,
        playerName: event.playerName,
        timestamp: event.timestamp,
      };
      setEvents((prev) => [feedEvent, ...prev].slice(0, 50));
      setUseFallback(false);
    },
    onError: (error) => {
      console.warn('Marketplace realtime error:', error);
      setUseFallback(true);
    },
  });

  // Fallback: simulate events when WebSocket is unavailable
  useEffect(() => {
    if (!useFallback || !autoConnect) return;

    const interval = setInterval(() => {
      setEvents((prev) => [generateMockEvent(), ...prev].slice(0, 50));
    }, 5000 + Math.random() * 5000);

    return () => clearInterval(interval);
  }, [useFallback, autoConnect]);

  const displayEvents = events.slice(0, maxDisplay);
  const displayConnectionStatus = useFallback ? 'disconnected' : connectionStatus;

  return (
    <div className="rounded-2xl border-2 border-secondary/30 backdrop-blur-[16px] bg-[rgba(17,17,17,0.7)] p-5">
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <svg
            className="h-5 w-5 text-secondary"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
            strokeWidth={2}
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              d="M13 10V3L4 14h7v7l9-11h-7z"
            />
          </svg>
          <h3 className="font-heading text-sm font-bold text-white">
            Live Feed
          </h3>
        </div>
        <div className="flex items-center gap-1.5">
          <span
            className={`h-2 w-2 rounded-full ${
              isConnected
                ? 'bg-green-400 animate-pulse'
                : useFallback
                  ? 'bg-yellow-400'
                  : 'bg-red-400'
            }`}
          />
          <span className="text-[10px] text-muted-foreground">
            {isConnected
              ? 'Connected'
              : useFallback
                ? 'Demo Mode'
                : displayConnectionStatus === 'connecting'
                  ? 'Connecting...'
                  : 'Disconnected'}
          </span>
        </div>
      </div>

      {/* Events List */}
      <div className="space-y-2">
        {displayEvents.map((event) => {
          const config = eventConfig[event.type];
          return (
            <div
              key={event.id}
              className={`flex items-center gap-3 rounded-xl border p-2.5 transition-all duration-300 ${config.bgColor}`}
            >
              {/* Event icon */}
              <span className="text-lg flex-shrink-0">{config.icon}</span>

              {/* Event details */}
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-1.5">
                  <span className={`text-[10px] font-semibold ${config.color}`}>
                    {config.label}
                  </span>
                  <span className="text-[9px] text-muted-foreground">
                    {timeAgo(event.timestamp)}
                  </span>
                </div>
                <p className="text-[11px] text-white truncate">
                  {event.itemName}
                </p>
                <p className="text-[10px] text-muted-foreground truncate">
                  by {event.playerName}
                </p>
              </div>

              {/* Price */}
              <div className="flex items-center gap-1 flex-shrink-0">
                <span className="text-yellow-400 text-xs">🪙</span>
                <span className="text-[11px] font-semibold text-yellow-300">
                  {formatGold(event.price)}
                </span>
              </div>
            </div>
          );
        })}
      </div>

      {/* Empty state */}
      {displayEvents.length === 0 && (
        <div className="text-center py-6">
          <p className="text-sm text-muted-foreground">No recent activity</p>
        </div>
      )}

      {/* Connection info */}
      <div className="mt-3 pt-3 border-t border-white/5 flex items-center justify-between text-[9px] text-muted-foreground">
        <span>
          {useFallback ? '📡 Showing demo data' : '🔄 Live updates enabled'}
        </span>
        {displayConnectionStatus === 'reconnecting' && (
          <span className="text-yellow-400">Reconnecting...</span>
        )}
      </div>
    </div>
  );
}

